CREATE TABLE IF NOT EXISTS t_p7983100_foam_cutting_app.users (id SERIAL PRIMARY KEY, last_name VARCHAR(100) NOT NULL, first_name VARCHAR(100) NOT NULL, middle_name VARCHAR(100), phone VARCHAR(20) UNIQUE NOT NULL, position VARCHAR(100) NOT NULL, role VARCHAR(20) NOT NULL DEFAULT 'operator', is_active BOOLEAN NOT NULL DEFAULT true, created_at TIMESTAMP NOT NULL DEFAULT NOW())